INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "まーたしかに、あのときの\nウヅキたちのゲリラLIVEは\nほんとにボロボロだったわね！", 1070031, 1, "", 7, "", 106031, 11, 1, 10);
INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "", 1070032, "", "", 7, "", 0, 91, "", "");
