INSERT INTO `v1_311c92688a3628be662f63ec05ccd0c2fe0e4b3640225443754ecfe654411eef` VALUES ("", "もうっ、キャルキャル～\nあんま言わないでよ～！\n私たちだってわかってるんだからさ～", 1070036, 1, "", 7, "", 112611, 11, 1, 10);
